class Solution {
    public int findMaxK(int[] nums) {
        int maxK = -1;
        for (int num : nums) {
            int negK = -num;
            if (nums.contains(negK) && negK > maxK) {
                maxK = negK;
            }
        }
        return maxK;
    }
}
